+    #[test]
+    fn test_prepare_scalar_rowid_subquery_limit_arms_query_fast_path() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE categories (id INTEGER PRIMARY KEY, name TEXT NOT NULL);")
+            .unwrap();
+        conn.execute(
+            "CREATE TABLE products (
+                id INTEGER PRIMARY KEY,
+                name TEXT NOT NULL,
+                category_id INTEGER
+            );",
+        )
+        .unwrap();
+
+        let stmt = conn
+            .prepare(
+                "SELECT p.name, \
+                        (SELECT c.name FROM categories c WHERE c.id = p.category_id) AS cat_name \
+                 FROM products p \
+                 LIMIT 2",
+            )
+            .unwrap();
+        assert!(matches!(
+            stmt.prepared_query_fast_path,
+            Some(super::PreparedQueryFastPath::SimpleLimitedScalarRowidSubquery { .. })
+        ));
+    }
+
