+            "CREATE TABLE products (
+                id INTEGER PRIMARY KEY,
+                name TEXT NOT NULL,
+                category_id INTEGER
+            );",
+        )
+        .unwrap();
+        conn.execute(
+            "INSERT INTO categories VALUES
+                (1, 'alpha'),
+                (2, 'beta');",
+        )
+        .unwrap();
+        conn.execute(
+            "INSERT INTO products VALUES
